<?php require_once dirname(__DIR__) . '/includes/auth.php'; require_admin(); require_once dirname(__DIR__).'/includes/mailer.php'; $pdo=db(); $message='';
if(($_SERVER['REQUEST_METHOD']??'')==='POST'){ $stmt=$pdo->prepare('SELECT t.*,s.client_id,c.* FROM email_templates t JOIN email_sequences s ON s.id=t.sequence_id JOIN clients c ON c.id=s.client_id WHERE t.id=?'); $stmt->execute([$_POST['template_id']]); $row=$stmt->fetch(); if($row){ $subscriber=['name'=>'Test Subscriber','email'=>config('admin_email'),'unsubscribe_token'=>'test-token']; $res=send_funnel_email($subscriber,$row,$row,config('admin_email')); $message=$res['success']?'Test sent.':'Test failed: '.$res['error']; }}
$templates=$pdo->query('SELECT t.id,t.subject,t.day_number,s.name sequence_name FROM email_templates t JOIN email_sequences s ON s.id=t.sequence_id ORDER BY s.name,t.day_number')->fetchAll(); include '_header.php'; ?>
<h1>Send Test Email</h1><?php if($message): ?><p class="card"><?=e($message)?></p><?php endif; ?><div class="card"><form method="post"><select name="template_id"><?php foreach($templates as $t): ?><option value="<?=$t['id']?>"><?=e($t['sequence_name'].' Day '.$t['day_number'].' - '.$t['subject'])?></option><?php endforeach; ?></select><button>Send to <?=e(config('admin_email'))?></button></form></div><?php include '_footer.php'; ?>
